{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "prompt",
            "prompt": "If the Bash command is a `git commit` operation, check: were any .sh files staged for this commit? If yes, verify that `bash -n` was run on each staged .sh file earlier in this conversation. If syntax checking was NOT done, BLOCK the commit and output: 'BLOCK: Run bash -n on all staged .sh files before committing. Staged .sh files: [list them]'. If syntax checking was already done and passed, output 'ALLOW'."
          }
        ]
      }
    ]
  }
}

